pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable2Step.sol";

contract FeeManager is Ownable2Step {
    uint256 public feeBps;
    uint256 public collected;

    error FeeTooHigh();
    error TransferFailed();

    event FeeUpdated(uint256 oldFee, uint256 newFee);
    event FeesWithdrawn(address indexed to, uint256 amount);

    constructor(address initialOwner) Ownable(initialOwner) {}

    function setFee(uint256 newFeeBps) external onlyOwner {
        if (newFeeBps > 1000) revert FeeTooHigh(); // hard cap 10%
        emit FeeUpdated(feeBps, newFeeBps);
        feeBps = newFeeBps;
    }

    function collect() external payable {
        collected += msg.value;
    }

    function withdrawFees(address payable to) external onlyOwner {
        uint256 amount = collected;
        collected = 0;
        (bool ok, ) = to.call{value: amount}("");
        if (!ok) revert TransferFailed();
        emit FeesWithdrawn(to, amount);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract OracleProxy {
    address public immutable trustedRelayer;
    uint256 public latestPrice;

    error NotAuthorized();

    event PriceUpdated(uint256 price, uint256 ts);

    constructor(address relayer) {
        require(relayer != address(0), "zero relayer");
        trustedRelayer = relayer;
    }

    // Use msg.sender, NEVER tx.origin
    modifier onlyRelayer() {
        if (msg.sender != trustedRelayer) revert NotAuthorized();
        _;
    }

    function pushPrice(uint256 price) external onlyRelayer {
        latestPrice = price;
        emit PriceUpdated(price, block.timestamp);
    }
}

