pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract TokenSale is ReentrancyGuard {
    IERC20 public immutable token;
    uint256 public immutable hardCap;
    uint256 public immutable rate; // tokens per wei
    uint256 public totalRaised;

    error CapExceeded();
    error ZeroValue();
    error TransferFailed();

    event Purchased(address indexed buyer, uint256 wei_, uint256 tokens);

    constructor(IERC20 _token, uint256 _hardCap, uint256 _rate) {
        require(address(_token) != address(0) && _hardCap > 0 && _rate > 0, "bad params");
        token = _token;
        hardCap = _hardCap;
        rate = _rate;
    }

    function buy() external payable nonReentrant {
        if (msg.value == 0) revert ZeroValue();

        // Solidity 0.8 reverts on overflow; explicit guard for cap
        uint256 newTotal = totalRaised + msg.value;
        if (newTotal > hardCap) revert CapExceeded();
        totalRaised = newTotal;

        uint256 amount = msg.value * rate; // overflow-checked
        bool ok = token.transfer(msg.sender, amount);
        if (!ok) revert TransferFailed();

        emit Purchased(msg.sender, msg.value, amount);
    }
}

