pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract PullPayments is ReentrancyGuard {
    mapping(address => uint256) public credits;

    error NoCredit();
    error TransferFailed();
    error LengthMismatch();

    event Credited(address indexed to, uint256 amount);
    event Claimed(address indexed by, uint256 amount);

    // Push to ledger, not to wallets — avoids DoS-by-revert
    function distribute(address[] calldata to, uint256[] calldata amounts) external payable {
        if (to.length != amounts.length) revert LengthMismatch();
        uint256 total;
        for (uint256 i = 0; i < to.length; ++i) {
            credits[to[i]] += amounts[i];
            total += amounts[i];
            emit Credited(to[i], amounts[i]);
        }
        require(total == msg.value, "value mismatch");
    }

    function claim() external nonReentrant {
        uint256 amount = credits[msg.sender];
        if (amount == 0) revert NoCredit();
        credits[msg.sender] = 0;

        (bool ok, ) = payable(msg.sender).call{value: amount}("");
        if (!ok) revert TransferFailed();
        emit Claimed(msg.sender, amount);
    }
}

