pragma solidity ^0.8.20;

import "@chainlink/contracts/src/v0.8/vrf/VRFConsumerBaseV2.sol";
import "@chainlink/contracts/src/v0.8/vrf/interfaces/VRFCoordinatorV2Interface.sol";

contract SecureLottery is VRFConsumerBaseV2 {
    VRFCoordinatorV2Interface private immutable coordinator;
    bytes32 private immutable keyHash;
    uint64 private immutable subId;

    address[] public players;
    address public lastWinner;
    uint256 public requestId;

    event WinnerRequested(uint256 requestId);
    event WinnerPicked(address indexed winner);

    constructor(address vrfCoord, bytes32 _keyHash, uint64 _subId)
        VRFConsumerBaseV2(vrfCoord)
    {
        coordinator = VRFCoordinatorV2Interface(vrfCoord);
        keyHash = _keyHash;
        subId = _subId;
    }

    function enter() external payable {
        require(msg.value >= 0.01 ether, "min entry");
        players.push(msg.sender);
    }

    function pickWinner() external {
        require(players.length > 0, "no players");
        requestId = coordinator.requestRandomWords(keyHash, subId, 3, 200000, 1);
        emit WinnerRequested(requestId);
    }

    function fulfillRandomWords(uint256, uint256[] memory words) internal override {
        address winner = players[words[0] % players.length];
        lastWinner = winner;
        delete players;
        (bool ok, ) = payable(winner).call{value: address(this).balance}("");
        require(ok, "payout failed");
        emit WinnerPicked(winner);
    }
}

