pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Permit.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract SafeToken is ERC20, ERC20Permit {
    constructor(uint256 initialSupply)
        ERC20("SafeToken", "SAFE")
        ERC20Permit("SafeToken")
    {
        _mint(msg.sender, initialSupply);
    }

    // Mitigation for approve front-running (a.k.a. ERC20 approve race)
    function increaseAllowance(address spender, uint256 added) external returns (bool) {
        _approve(msg.sender, spender, allowance(msg.sender, spender) + added);
        return true;
    }

    function decreaseAllowance(address spender, uint256 sub) external returns (bool) {
        uint256 current = allowance(msg.sender, spender);
        require(current >= sub, "below zero");
        _approve(msg.sender, spender, current - sub);
        return true;
    }
}
// Note: ERC20Permit binds signatures to chainId via EIP-712 domain separator,
// preventing cross-chain replay automatically.

