pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/EIP712.sol";

contract WhitelistMint is ERC721, EIP712 {
    using ECDSA for bytes32;

    address public immutable signer;
    uint256 public nextId;
    mapping(bytes32 => bool) public usedDigests; // replay protection

    bytes32 private constant MINT_TYPEHASH =
        keccak256("Mint(address to,uint256 nonce,uint256 deadline)");

    error BadSignature();
    error AlreadyUsed();
    error Expired();

    constructor(address _signer)
        ERC721("WL", "WL")
        EIP712("WhitelistMint", "1")
    {
        signer = _signer;
    }

    function mint(uint256 nonce, uint256 deadline, bytes calldata sig) external {
        if (block.timestamp > deadline) revert Expired();

        bytes32 digest = _hashTypedDataV4(
            keccak256(abi.encode(MINT_TYPEHASH, msg.sender, nonce, deadline))
        );
        if (usedDigests[digest]) revert AlreadyUsed();
        if (digest.recover(sig) != signer) revert BadSignature();

        usedDigests[digest] = true;
        _safeMint(msg.sender, ++nextId); // _safeMint checks ERC721Receiver
    }
}

