pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract MiniAMM is ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable token0;
    IERC20 public immutable token1;
    uint112 private reserve0;
    uint112 private reserve1;

    error Expired();
    error Slippage();
    error ZeroAmount();

    event Swap(address indexed sender, uint256 amountIn, uint256 amountOut, bool zeroForOne);

    constructor(IERC20 _t0, IERC20 _t1) {
        token0 = _t0;
        token1 = _t1;
    }

    function _getAmountOut(uint256 amountIn, uint256 rIn, uint256 rOut) internal pure returns (uint256) {
        uint256 amountInWithFee = amountIn * 997;
        return (amountInWithFee * rOut) / (rIn * 1000 + amountInWithFee);
    }

    function swap(
        bool zeroForOne,
        uint256 amountIn,
        uint256 minOut,    // user-supplied slippage guard against sandwich
        uint256 deadline
    ) external nonReentrant returns (uint256 amountOut) {
        if (block.timestamp > deadline) revert Expired();
        if (amountIn == 0) revert ZeroAmount();

        (IERC20 tokenIn, IERC20 tokenOut, uint256 rIn, uint256 rOut) =
            zeroForOne ? (token0, token1, uint256(reserve0), uint256(reserve1))
                       : (token1, token0, uint256(reserve1), uint256(reserve0));

        tokenIn.safeTransferFrom(msg.sender, address(this), amountIn);
        amountOut = _getAmountOut(amountIn, rIn, rOut);
        if (amountOut < minOut) revert Slippage();

        tokenOut.safeTransfer(msg.sender, amountOut);

        // Update reserves from real balances (resists donation/inflation tricks)
        reserve0 = uint112(token0.balanceOf(address(this)));
        reserve1 = uint112(token1.balanceOf(address(this)));

        emit Swap(msg.sender, amountIn, amountOut, zeroForOne);
    }
}

