pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract Treasury {
    using SafeERC20 for IERC20;

    address public immutable owner;

    error NotOwner();

    constructor(address _owner) {
        owner = _owner;
    }

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    // SafeERC20 handles tokens that don't return bool (USDT, BNB, etc.)
    // and reverts on failure instead of returning false silently.
    function pull(IERC20 token, address from, uint256 amount) external onlyOwner {
        token.safeTransferFrom(from, address(this), amount);
    }

    function push(IERC20 token, address to, uint256 amount) external onlyOwner {
        token.safeTransfer(to, amount);
    }

    // forceApprove handles tokens that require allowance to be 0 before re-approve
    function approveSpender(IERC20 token, address spender, uint256 amount) external onlyOwner {
        token.forceApprove(spender, amount);
    }
}

