pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/EIP712.sol";

contract Multisig is EIP712 {
    using ECDSA for bytes32;

    address[] public signers;
    uint256 public threshold;
    uint256 public nonce; // strictly increasing → no replay

    bytes32 private constant EXEC_TYPEHASH =
        keccak256("Exec(address to,uint256 value,bytes data,uint256 nonce)");

    error BadThreshold();
    error NotSigner();
    error DuplicateSigner();
    error CallFailed();

    event Executed(address indexed to, uint256 value, bytes data, uint256 nonce);

    constructor(address[] memory _signers, uint256 _threshold)
        EIP712("Multisig", "1")
    {
        if (_threshold == 0 || _threshold > _signers.length) revert BadThreshold();
        signers = _signers;
        threshold = _threshold;
    }

    function isSigner(address a) public view returns (bool) {
        for (uint256 i = 0; i < signers.length; ++i) if (signers[i] == a) return true;
        return false;
    }

    function exec(address to, uint256 value, bytes calldata data, bytes[] calldata sigs) external {
        bytes32 digest = _hashTypedDataV4(
            keccak256(abi.encode(EXEC_TYPEHASH, to, value, keccak256(data), nonce))
        );
        nonce += 1; // increment first to block reentrant exec()

        address last;
        uint256 valid;
        for (uint256 i = 0; i < sigs.length; ++i) {
            address recovered = digest.recover(sigs[i]);
            if (!isSigner(recovered)) revert NotSigner();
            if (recovered <= last) revert DuplicateSigner(); // require strictly increasing
            last = recovered;
            valid++;
        }
        require(valid >= threshold, "not enough sigs");

        // Use call (NOT delegatecall) to avoid storage hijacking of this contract
        (bool ok, ) = to.call{value: value}(data);
        if (!ok) revert CallFailed();

        emit Executed(to, value, data, nonce - 1);
    }

    receive() external payable {}
}

