pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable2Step.sol";

contract LinearVesting is Ownable2Step {
    using SafeERC20 for IERC20;

    IERC20 public immutable token;
    address public immutable beneficiary;
    uint64  public immutable start;
    uint64  public immutable cliff;
    uint64  public immutable duration;

    uint256 public released;
    bool public revoked;

    error Revoked();
    error NothingToRelease();

    event Released(uint256 amount);
    event RevokedAndRecovered(uint256 amount);

    constructor(
        IERC20 _token,
        address _beneficiary,
        uint64 _start,
        uint64 _cliff,
        uint64 _duration,
        address admin
    ) Ownable(admin) {
        require(_beneficiary != address(0) && _duration > 0 && _cliff <= _duration, "bad cfg");
        token = _token;
        beneficiary = _beneficiary;
        start = _start;
        cliff = _cliff;
        duration = _duration;
    }

    function vested(uint256 totalAllocation) public view returns (uint256) {
        if (block.timestamp < start + cliff) return 0;
        if (block.timestamp >= start + duration) return totalAllocation;
        // multiply BEFORE divide to minimize precision loss
        return (totalAllocation * (block.timestamp - start)) / duration;
    }

    function release() external {
        if (revoked) revert Revoked();
        uint256 totalAllocation = token.balanceOf(address(this)) + released;
        uint256 amount = vested(totalAllocation) - released;
        if (amount == 0) revert NothingToRelease();
        released += amount;
        token.safeTransfer(beneficiary, amount);
        emit Released(amount);
    }

    // Explicit revoke recovers UNVESTED portion only — keeps already-vested tokens claimable.
    function revoke() external onlyOwner {
        require(!revoked, "already");
        uint256 totalAllocation = token.balanceOf(address(this)) + released;
        uint256 vestedNow = vested(totalAllocation);
        uint256 unreleased = vestedNow - released;
        revoked = true;
        uint256 refund = token.balanceOf(address(this)) - unreleased;
        if (refund > 0) token.safeTransfer(owner(), refund);
        emit RevokedAndRecovered(refund);
    }
}

