pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Auction is ReentrancyGuard {
    address public immutable beneficiary;
    uint256 public immutable endTime;

    address public highestBidder;
    uint256 public highestBid;

    mapping(address => uint256) public refunds; // pull pattern → DoS-resistant
    bool public ended;

    error AuctionEnded();
    error NotEnded();
    error BidTooLow();
    error TransferFailed();

    event NewHighestBid(address indexed bidder, uint256 amount);
    event Withdrawn(address indexed who, uint256 amount);
    event AuctionFinalized(address winner, uint256 amount);

    constructor(address _beneficiary, uint256 biddingTime) {
        beneficiary = _beneficiary;
        endTime = block.timestamp + biddingTime;
    }

    function bid() external payable {
        if (block.timestamp >= endTime) revert AuctionEnded();
        if (msg.value <= highestBid) revert BidTooLow();

        if (highestBidder != address(0)) {
            // Don't push refund — store it. Old bidder withdraws themselves.
            refunds[highestBidder] += highestBid;
        }
        highestBidder = msg.sender;
        highestBid = msg.value;
        emit NewHighestBid(msg.sender, msg.value);
    }

    function withdraw() external nonReentrant {
        uint256 amount = refunds[msg.sender];
        require(amount > 0, "nothing");
        refunds[msg.sender] = 0;
        (bool ok, ) = payable(msg.sender).call{value: amount}("");
        if (!ok) revert TransferFailed();
        emit Withdrawn(msg.sender, amount);
    }

    function finalize() external nonReentrant {
        if (block.timestamp < endTime) revert NotEnded();
        require(!ended, "done");
        ended = true;
        (bool ok, ) = payable(beneficiary).call{value: highestBid}("");
        if (!ok) revert TransferFailed();
        emit AuctionFinalized(highestBidder, highestBid);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface AggregatorV3Interface {
    function latestRoundData() external view returns (
        uint80 roundId, int256 answer, uint256 startedAt,
        uint256 updatedAt, uint80 answeredInRound
    );
    function decimals() external view returns (uint8);
}

contract PriceConsumer {
    AggregatorV3Interface public immutable feed;
    AggregatorV3Interface public immutable sequencerUptimeFeed; // L2 only; address(0) on L1
    uint256 public immutable maxStaleness;
    uint256 public constant GRACE_PERIOD = 3600;

    error StalePrice();
    error InvalidPrice();
    error SequencerDown();
    error GracePeriodNotOver();

    constructor(
        AggregatorV3Interface _feed,
        AggregatorV3Interface _sequencerFeed,
        uint256 _maxStaleness
    ) {
        feed = _feed;
        sequencerUptimeFeed = _sequencerFeed;
        maxStaleness = _maxStaleness;
    }

    function getPrice() external view returns (uint256 price, uint8 decimals) {
        // L2 sequencer liveness check (skip if not on L2)
        if (address(sequencerUptimeFeed) != address(0)) {
            (, int256 answer, uint256 startedAt, , ) = sequencerUptimeFeed.latestRoundData();
            if (answer != 0) revert SequencerDown(); // 1 = down
            if (block.timestamp - startedAt < GRACE_PERIOD) revert GracePeriodNotOver();
        }

        (uint80 roundId, int256 answer, , uint256 updatedAt, uint80 answeredInRound) =
            feed.latestRoundData();

        if (answer <= 0) revert InvalidPrice();
        if (answeredInRound < roundId) revert StalePrice();
        if (block.timestamp - updatedAt > maxStaleness) revert StalePrice();

        return (uint256(answer), feed.decimals());
    }
}
